const normalizedData = $('Normalize Input').item.json;
const rawContent = $input.item.json.choices[0].message.content;
const attempt = normalizedData.attempt || 1;

// Clean markdown if present
const cleanContent = rawContent.replace(/```json/g, '').replace(/```/g, '').trim();

// Parse JSON
let content;
try {
  content = JSON.parse(cleanContent);
} catch(e) {
  content = { product_copy: { headline: 'N/A', subheadline: 'N/A', body_copy: cleanContent, cta: 'N/A' }, email_sequence: [], ad_hooks: [], content_score: 5 };
}

const revisionText = normalizedData.revision_notes ? ' (Revision Attempt ' + attempt + ')' : '';

// Format into human readable Band message
const messageContent = `@[YOUR_BAND_ORG]/[YOUR_AGENT3_HANDLE] ✍️ CONTENT READY${revisionText}\n\n📦 Product: ${normalizedData.product_name}\n🔄 Attempt: ${attempt}/3\n\n📣 Headline:\n${content.product_copy?.headline}\n\n📝 Subheadline:\n${content.product_copy?.subheadline}\n\n💬 Body Copy:\n${content.product_copy?.body_copy}\n\n🔘 CTA: ${content.product_copy?.cta}\n\n📧 Email Sequence:\n${(content.email_sequence || []).map((e, i) => `Email ${i+1}: ${e.subject}`).join('\n')}\n\n🎯 Ad Hooks:\n${(content.ad_hooks || []).map((h, i) => `${i+1}. ${h}`).join('\n')}\n\n⭐ Self Score: ${content.content_score}/10\n\n➡️ ACTION: Score this content. Below 7 send back with revision notes. 7 or above approve and pass to CampaignAgent.`;

return [{
  json: {
    product_name: normalizedData.product_name,
    product_description: normalizedData.product_description,
    target_audience: normalizedData.target_audience,
    chat_id: normalizedData.chat_id,
    research_data: normalizedData.research_data,
    content_data: cleanContent,
    attempt: attempt,
    band_message: messageContent,
    band_api_key: '[REDACTED_BAND_API_KEY]'
  }
}];
